//! convergio-mcp-server binary entry point.
//!
//! Exposes the Convergio daemon as an MCP server over stdio or
//! Streamable HTTP transport. Uses the rmcp SDK for protocol handling.
//! Tool definitions are fetched dynamically from the daemon at startup.
//! CRITICAL: stdout is JSON-RPC protocol only. All logs must go to stderr.

use std::sync::Arc;

use clap::Parser;
use convergio_mcp::handler::ConvergioHandler;
use convergio_mcp::profile::Profile;
use convergio_mcp::registry::fetch_tool_defs;
use rmcp::transport::streamable_http_server::{
    session::local::LocalSessionManager, StreamableHttpServerConfig, StreamableHttpService,
};
use rmcp::ServiceExt;

#[derive(Parser)]
#[command(name = "convergio-mcp-server", version, about = "Convergio MCP server")]
struct Cli {
    /// Transport: "stdio" (default) or "streamable-http"
    #[arg(long, default_value = "stdio")]
    transport: String,

    /// Bind address for Streamable HTTP transport (only with --transport streamable-http)
    #[arg(long, default_value = "127.0.0.1:8421")]
    bind: String,
}

#[tokio::main]
async fn main() -> anyhow::Result<()> {
    tracing_subscriber::fmt()
        .with_writer(std::io::stderr)
        .with_env_filter(
            tracing_subscriber::EnvFilter::try_from_default_env()
                .unwrap_or_else(|_| tracing_subscriber::EnvFilter::new("warn")),
        )
        .init();

    let cli = Cli::parse();

    let ring: u8 = std::env::var("CONVERGIO_MCP_RING")
        .ok()
        .and_then(|v| v.parse().ok())
        .unwrap_or(3);

    let daemon_url = std::env::var("CONVERGIO_DAEMON_URL")
        .unwrap_or_else(|_| "http://localhost:8420".to_string());

    let token = std::env::var("CONVERGIO_API_TOKEN").ok();

    // Discover tools from daemon (falls back to static defs if unreachable)
    let tools = fetch_tool_defs(&daemon_url, token.as_deref());
    let profile = Profile::from_env();
    eprintln!(
        "Discovered {} MCP tools, profile={:?} (effective: {})",
        tools.len(),
        profile,
        convergio_mcp::profile::filter_by_profile(&tools, profile).len()
    );

    tracing::info!(ring, daemon_url = %daemon_url, transport = %cli.transport,
        tools = tools.len(), ?profile, "starting");

    match cli.transport.as_str() {
        "stdio" => {
            let handler =
                ConvergioHandler::new(ring, profile, &daemon_url, token.as_deref(), tools);
            let transport = rmcp::transport::stdio();
            let server = handler.serve(transport).await?;
            server.waiting().await?;
        }
        "streamable-http" | "sse" => {
            let tools = Arc::new(tools);
            let d = daemon_url.clone();
            let t = token.clone();
            let service = StreamableHttpService::new(
                move || {
                    Ok(ConvergioHandler::new(
                        ring,
                        profile,
                        &d,
                        t.as_deref(),
                        (*tools).clone(),
                    ))
                },
                Arc::new(LocalSessionManager::default()),
                StreamableHttpServerConfig::default(),
            );

            let listener = tokio::net::TcpListener::bind(&cli.bind).await?;
            eprintln!("MCP Streamable HTTP on http://{}", cli.bind);
            loop {
                let (stream, _) = listener.accept().await?;
                let svc = hyper_util::service::TowerToHyperService::new(service.clone());
                let io = hyper_util::rt::TokioIo::new(stream);
                tokio::spawn(async move {
                    let builder = hyper_util::server::conn::auto::Builder::new(
                        hyper_util::rt::TokioExecutor::new(),
                    );
                    let conn = builder.serve_connection(io, svc);
                    if let Err(e) = conn.await {
                        eprintln!("Connection error: {e}");
                    }
                });
            }
        }
        other => {
            eprintln!("Unknown transport: {other}. Use 'stdio' or 'streamable-http'.");
            std::process::exit(1);
        }
    }

    Ok(())
}

//! Tool profile filtering for MCP context optimization.
//!
//! Profiles control which tools are exposed to the LLM client.
//! `Compact` exposes ~30 essential tools, saving ~10K tokens of context.
//! `Full` exposes all tools (default for backward compatibility).

use crate::registry::ToolDef;

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Profile {
    /// All tools visible (default).
    Full,
    /// Essential tools only (~30). Saves ~10K tokens.
    Compact,
    /// Single cvg_ceo tool — routes everything via LLM.
    Ceo,
}

impl Profile {
    pub fn from_env() -> Self {
        match std::env::var("CONVERGIO_MCP_PROFILE")
            .unwrap_or_default()
            .to_lowercase()
            .as_str()
        {
            "compact" | "c" => Self::Compact,
            "ceo" => Self::Ceo,
            _ => Self::Full,
        }
    }
}

/// Tools included in compact profile. Covers the full agent workflow:
/// solve → plan → execute → evidence → validate, plus essential ops.
const COMPACT_TOOLS: &[&str] = &[
    // Workflow pipeline
    "cvg_solve",
    "cvg_create_plan",
    "cvg_execute_plan",
    "cvg_how_to",
    "cvg_help",
    // Health & diagnostics
    "cvg_health",
    "cvg_doctor_run",
    "cvg_node_readiness",
    // Plan lifecycle
    "cvg_list_plans",
    "cvg_get_plan",
    "cvg_get_execution_tree",
    "cvg_start_plan",
    "cvg_cancel_plan",
    "cvg_resume_plan",
    "cvg_force_resume_plan",
    "cvg_force_complete_plan",
    "cvg_plan_readiness",
    "cvg_plan_import",
    "cvg_validate_plan",
    "cvg_review_plan",
    // Task execution (gate chain)
    "cvg_update_task",
    "cvg_complete_task",
    "cvg_wave_complete",
    "cvg_record_evidence",
    "cvg_evidence_preflight",
    // Agent management
    "cvg_spawn_agent",
    "cvg_list_agent_catalog",
    "cvg_get_agent",
    // Workspace + code graph
    "cvg_check_worktree_owner",
    "cvg_workspace_gc",
    "cvg_codegraph_expand",
    "cvg_codegraph_package_deps",
    // Knowledge store
    "cvg_knowledge_search",
    "cvg_knowledge_write",
    // Org basics
    "cvg_list_orgs",
    "cvg_get_org",
    // Delegation
    "cvg_delegate_spawn",
    "cvg_delegation_status",
    "cvg_delegation_list",
    // Misc essentials
    "cvg_notify",
    "cvg_cost_summary",
];

/// Check if a tool name is included in the given profile.
pub fn is_in_profile(name: &str, profile: Profile) -> bool {
    match profile {
        Profile::Full => true,
        Profile::Compact => COMPACT_TOOLS.contains(&name),
        Profile::Ceo => name == "cvg_ceo",
    }
}

/// Filter tool list by profile.
pub fn filter_by_profile(defs: &[ToolDef], profile: Profile) -> Vec<&ToolDef> {
    match profile {
        Profile::Full => defs.iter().collect(),
        Profile::Compact => defs
            .iter()
            .filter(|t| COMPACT_TOOLS.contains(&t.name.as_str()))
            .collect(),
        Profile::Ceo => defs.iter().filter(|t| t.name == "cvg_ceo").collect(),
    }
}

#[cfg(test)]
mod profile_tests {
    use super::*;
    use crate::registry::HttpMethod;
    use crate::ring::Ring;
    use serde_json::json;

    fn make_tool(name: &str) -> ToolDef {
        ToolDef {
            name: name.into(),
            description: "test".into(),
            method: HttpMethod::Get,
            path: "/test".into(),
            input_schema: json!({}),
            min_ring: Ring::Trusted,
            path_params: vec![],
        }
    }

    #[test]
    fn compact_filters_non_essential() {
        let tools: Vec<ToolDef> = vec![
            make_tool("cvg_health"),
            make_tool("cvg_solve"),
            make_tool("cvg_list_snapshots"),
            make_tool("cvg_tenancy_audit"),
        ];
        let filtered = filter_by_profile(&tools, Profile::Compact);
        let names: Vec<&str> = filtered.iter().map(|t| t.name.as_str()).collect();
        assert!(names.contains(&"cvg_health"));
        assert!(names.contains(&"cvg_solve"));
        assert!(!names.contains(&"cvg_list_snapshots"));
        assert!(!names.contains(&"cvg_tenancy_audit"));
    }

    #[test]
    fn full_passes_everything() {
        let tools: Vec<ToolDef> = vec![make_tool("cvg_health"), make_tool("cvg_list_snapshots")];
        let filtered = filter_by_profile(&tools, Profile::Full);
        assert_eq!(filtered.len(), 2);
    }

    #[test]
    fn compact_whitelist_has_reasonable_size() {
        assert!(COMPACT_TOOLS.len() >= 25);
        assert!(COMPACT_TOOLS.len() <= 45);
    }

    #[test]
    fn ceo_profile_exposes_only_cvg_ceo() {
        let tools: Vec<ToolDef> = vec![
            make_tool("cvg_ceo"),
            make_tool("cvg_health"),
            make_tool("cvg_solve"),
        ];
        let filtered = filter_by_profile(&tools, Profile::Ceo);
        assert_eq!(filtered.len(), 1);
        assert_eq!(filtered[0].name, "cvg_ceo");
    }

    #[test]
    fn ceo_profile_is_in_profile() {
        assert!(is_in_profile("cvg_ceo", Profile::Ceo));
        assert!(!is_in_profile("cvg_health", Profile::Ceo));
        assert!(!is_in_profile("cvg_solve", Profile::Ceo));
    }
}

//! Declarative tool registry: ToolDef maps MCP tool names to daemon HTTP routes.
//!
//! Two sources of tool definitions:
//! 1. **Dynamic**: fetched from daemon at `/api/meta/mcp-tools` (auto-discovers extensions)
//! 2. **Static**: synthetic tools in `registry_defs` (composite workflows not tied to a single route)
//!
//! Dynamic tools are preferred and refreshed on each startup.

use serde_json::Value;

use crate::ring::Ring;

// ── ToolDef ──────────────────────────────────────────────────────────────────

#[derive(Debug, Clone)]
pub struct ToolDef {
    pub name: String,
    pub description: String,
    pub method: HttpMethod,
    pub path: String,
    pub input_schema: Value,
    pub min_ring: Ring,
    pub path_params: Vec<String>,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum HttpMethod {
    Get,
    Post,
    Put,
    Delete,
}

// ── Dynamic discovery ────────────────────────────────────────────────────────

/// Fetch tool definitions from the daemon's `/api/meta/mcp-tools` endpoint.
/// Falls back to static defs from `registry_defs` if daemon is unreachable.
pub fn fetch_tool_defs(daemon_url: &str, token: Option<&str>) -> Vec<ToolDef> {
    let url = format!("{daemon_url}/api/meta/mcp-tools");
    let client = reqwest::blocking::Client::new();
    let mut req = client.get(&url);
    if let Some(t) = token {
        req = req.header("Authorization", format!("Bearer {t}"));
    }

    let dynamic = match req.send().and_then(|r| r.json::<serde_json::Value>()) {
        Ok(body) => body
            .get("tools")
            .and_then(|t| t.as_array())
            .map(|tools| tools.iter().filter_map(parse_mcp_tool_def).collect())
            .unwrap_or_default(),
        Err(_) => Vec::new(),
    };

    // Merge: dynamic tools take precedence, static fill gaps (synthetic tools)
    let static_defs = crate::registry_defs::all_defs();
    if dynamic.is_empty() {
        return static_defs;
    }
    let mut merged = dynamic;
    let names: std::collections::HashSet<String> = merged.iter().map(|t| t.name.clone()).collect();
    for def in static_defs {
        if !names.contains(&def.name) {
            merged.push(def);
        }
    }
    merged
}

fn parse_mcp_tool_def(v: &Value) -> Option<ToolDef> {
    let name = v.get("name")?.as_str()?;
    let description = v.get("description")?.as_str()?;
    let method = match v.get("method")?.as_str()? {
        "GET" => HttpMethod::Get,
        "POST" => HttpMethod::Post,
        "PUT" => HttpMethod::Put,
        "DELETE" => HttpMethod::Delete,
        _ => return None,
    };
    let ring = match v.get("min_ring")?.as_str()? {
        "sandboxed" => Ring::Sandboxed,
        "community" => Ring::Community,
        "trusted" => Ring::Trusted,
        "core" => Ring::Core,
        _ => Ring::Trusted,
    };
    let path_params: Vec<String> = v
        .get("path_params")
        .and_then(|p| p.as_array())
        .map(|arr| {
            arr.iter()
                .filter_map(|x| x.as_str().map(String::from))
                .collect()
        })
        .unwrap_or_default();

    Some(ToolDef {
        name: name.to_string(),
        description: description.to_string(),
        method,
        path: v.get("path")?.as_str()?.to_string(),
        input_schema: v
            .get("input_schema")
            .cloned()
            .unwrap_or(Value::Object(Default::default())),
        min_ring: ring,
        path_params,
    })
}

// ── Registry queries ─────────────────────────────────────────────────────────

pub fn list_tool_defs_filtered(defs: &[ToolDef], caller_ring: Ring) -> Vec<&ToolDef> {
    defs.iter()
        .filter(|t| caller_ring.can_access(t.min_ring))
        .collect()
}

pub fn find_tool_def<'a>(defs: &'a [ToolDef], name: &str) -> Option<&'a ToolDef> {
    defs.iter().find(|t| t.name == name)
}

// ── URL builder ──────────────────────────────────────────────────────────────

pub fn build_url(def: &ToolDef, args: &Value, daemon_url: &str) -> String {
    let mut path = def.path.clone();
    for param in &def.path_params {
        if let Some(val) = args.get(param.as_str()) {
            let replacement = match val {
                Value::Number(n) => n.to_string(),
                Value::String(s) => s.clone(),
                _ => val.to_string(),
            };
            path = path.replace(&format!(":{param}"), &replacement);
        }
    }
    if def.method == HttpMethod::Get {
        if let Some(obj) = args.as_object() {
            let qs: Vec<String> = obj
                .iter()
                .filter(|(k, v)| !def.path_params.contains(k) && !v.is_null())
                .map(|(k, v)| {
                    let val = match v {
                        Value::String(s) => s.clone(),
                        _ => v.to_string(),
                    };
                    format!("{k}={val}")
                })
                .collect();
            if !qs.is_empty() {
                return format!("{daemon_url}{path}?{}", qs.join("&"));
            }
        }
    }
    format!("{daemon_url}{path}")
}

